// frontend/src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import { Pie, Bar } from "react-chartjs-2";
import "chart.js/auto";
import './Dashboard.css';


const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };

    fetchStats();
  }, []);

  if (!stats) return <div>Loading dashboard data...</div>;

  // Pie Chart Data
  const pieData = {
    labels: ["Free Rooms", "Occupied Rooms"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4CAF50", "#F44336"],
      },
    ],
  };

  // Bar Chart Data
  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
      },
    ],
  };

  return (
    <div className="dashboard">
      <h1>📊 Classroom Availability Dashboard</h1>

      <div className="dashboard__grid">
        <div className="dashboard__circle-chart large">
          {/* Big Donut Chart - Free/Occupied/Reserved */}
          <Pie data={pieData} />
        </div>

        <div className="dashboard__circle-chart small">
          <Pie data={performanceChart} />
        </div>
        <div className="dashboard__circle-chart small">
          <Pie data={seoChart} />
        </div>
        <div className="dashboard__circle-chart small">
          <Pie data={accessibilityChart} />
        </div>
        <div className="dashboard__circle-chart small">
          <Pie data={bestPracticeChart} />
        </div>

        <div className="dashboard__bar-chart">
          <Bar data={loadTimeData} />
        </div>
      </div>

      {/* You can place a section below for date, summary, or logs */}
      <div className="dashboard__bottom-row">
        <p><strong>Last Updated:</strong> Apr 6, 2025</p>
        {/* Optionally add table or description */}
      </div>
    </div>

  );
};

export default Dashboard;
